    name: "My Contact Point",
    emails: [{
        addresses: [
            "one@company.org",
            "two@company.org",
        ],
        message: "{{ len .Alerts.Firing }} firing.",
        subject: "{{ template \"default.title\" .}}",
        singleEmail: true,
        disableResolveMessage: false,
    }],
});
