    name: "test-anything",
    rules: {
        entities: [{
            type: "Service",
            name: "workload | service | job",
            scope: {
                namespace: "namespace",
                env: "asserts_env",
                site: "asserts_site",
            },
            lookup: {
                workload: "workload | deployment | statefulset | daemonset | replicaset",
                service: "service",
                job: "job",
                proxy_job: "job",
            },
            definedBies: [
                {
                    query: "up{job!=''}",
                    disabled: false,
                    labelValues: {
                        service: "service",
                        job: "job",
                    },
                    literals: {
                        _source: "up_query",
                    },
                },
                {
                    query: "up{job='disabled'}",
                    disabled: true,
                },
            ],
        }],
    },
});
