    name: "custom-conditional-rules",
    active: true,
    groups: [{
        name: "environment_specific_rules",
        interval: "30s",
        rules: [
            {
                alert: "TestAlert",
                expr: "up == 0",
                duration: "1m",
                labels: {
                    severity: "info",
                },
                annotations: {
                    summary: "Test alert that is disabled in production",
                },
                disableInGroups: ["production"],
            },
            {
                alert: "CriticalAlert",
                expr: "up == 0",
                duration: "30s",
                labels: {
                    severity: "critical",
                },
                annotations: {
